function walletInUse(id){ return AppState.transactions.some(t=>t.wallet===id||t.targetWallet===id) || AppState.recurring.some(r=>r.wallet===id); }

function renderWalletsList(){
  const box=document.getElementById('wallets-list'); if(!box) return;
  box.innerHTML='';
  if(!AppState.wallets.length){ box.innerHTML=`<div class="mgr-empty">${tr('wallets_empty')}</div>`; return; }
  AppState.wallets.forEach(w=>{
    const row=document.createElement('div');
    row.className='mgr-row';
    row.innerHTML=`
      <button type="button" class="mgr-color" style="background:${escapeHtml(w.color||'#8b5cf6')}" onclick="openColorPicker('wallet','${w.id}')"></button>
      <input type="text" class="mgr-name-inline" value="${escapeHtml(w.name)}" placeholder="${tr('common_name')}" onchange="updateWallet('${w.id}','name',this.value)">
      <select style="flex:0 0 82px" onchange="updateWallet('${w.id}','currency',this.value)">
        ${CURRENCY_LIST.map(c=>`<option value="${c}" ${(w.currency||'UAH')===c?'selected':''}>${c}</option>`).join('')}
      </select>
      <button class="mgr-del" onclick="deleteWallet('${w.id}')" aria-label="${tr('common_delete')}">${window.Icon('trash')}</button>`;
    box.appendChild(row);
    row.querySelectorAll('select').forEach(enhanceSelect);
  });
}

export const updateWallet = function(id,field,value){
  const w=walletById(id); if(!w) return;
  if(field==='name') w.name=String(value).trim()||tr('wallets_default_name');
  else if(field==='currency'){ w.currency=value; if(value!=='UAH' && AppState.currencyRates[value]===undefined) AppState.currencyRates[value]=SEED_RATES[value]||1; }
  else w[field]=value;
  saveConfigLocal(); scheduleSave();
  renderFinance(); refreshWalletSelects();
};

const addWallet = async function(){
  const name=await uiPrompt(tr('wallets_add_prompt'),'',tr('wallets_new_default'));
  if(name===null) return;
  const color=PALETTE[AppState.wallets.length%PALETTE.length];
  AppState.wallets.push({id:uid('w'), name:name.trim()||tr('wallets_new_default'), color, icon:'card', currency:'UAH'});
  saveConfigLocal(); scheduleSave();
  renderWalletsList(); renderFinance(); refreshWalletSelects();
};

const deleteWallet = async function(id){
  if(AppState.wallets.length<=1){ showToast(tr('wallets_need_one'),'xmark'); return; }
  if(walletInUse(id)){ showToast(tr('wallets_in_use'),'xmark'); return; }
  if(!(await uiConfirm(tr('wallets_delete_confirm'),{title:tr('wallets_delete_title'),okText:tr('common_delete'),danger:true}))) return;
  AppState.wallets=AppState.wallets.filter(w=>w.id!==id);
  saveConfigLocal(); scheduleSave();
  renderWalletsList(); renderFinance(); refreshWalletSelects();
};

