const WIDGET_DEFS=[
  {key:'rates', icon:'swap', color:'#3b82f6', titleKey:'widgets_item_rates', subKey:'widgets_item_rates_sub'},
  {key:'converter', icon:'swap', color:'#0ea5e9', titleKey:'widgets_item_converter', subKey:'widgets_item_converter_sub'},
  {key:'analytics', icon:'pie', color:'#ec4899', titleKey:'widgets_item_analytics', subKey:'widgets_item_analytics_sub'},
  {key:'chart', icon:'barChart', color:'#f59e0b', titleKey:'widgets_item_chart', subKey:'widgets_item_chart_sub'},
  {key:'goals', icon:'flag', color:'#10b981', titleKey:'widgets_item_goals', subKey:'widgets_item_goals_sub'},
];

function renderWidgetsList(){
  const box=document.getElementById('widgets-list'); if(!box) return;
  const defByKey=Object.fromEntries(WIDGET_DEFS.map(w=>[w.key,w]));
  box.innerHTML=AppState.widgetOrder.map((key,i)=>{
    const w=defByKey[key]; if(!w) return '';
    return `
    <div class="settings-row" style="cursor:default">
      <span class="icon-badge" style="background:${w.color}">${window.Icon(w.icon)}</span>
      <div class="settings-row-text">
        <div class="settings-row-title">${tr(w.titleKey)}</div>
        <div class="settings-row-sub">${tr(w.subKey)}</div>
      </div>
      <div class="widget-reorder-col">
        <button type="button" class="widget-reorder-btn" ${i===0?'disabled':''} onclick="moveWidget('${key}',-1)" aria-label="${tr('widgets_move_up')}">${window.Icon('chevron')}</button>
        <button type="button" class="widget-reorder-btn widget-reorder-down" ${i===AppState.widgetOrder.length-1?'disabled':''} onclick="moveWidget('${key}',1)" aria-label="${tr('widgets_move_down')}">${window.Icon('chevron')}</button>
      </div>
      <label class="toggle">
        <input type="checkbox" ${AppState.widgets[key]!==false?'checked':''} onchange="toggleWidget('${key}', this.checked)">
        <span class="toggle-track"></span>
      </label>
    </div>`;
  }).join('');
}

const toggleWidget = function(key, on){
  AppState.widgets[key]=!!on;
  saveConfigLocal(); scheduleSave();
  applyWidgetVisibility();
};

const moveWidget = function(key, dir){
  const i=AppState.widgetOrder.indexOf(key);
  const j=i+dir;
  if(i<0||j<0||j>=AppState.widgetOrder.length) return;
  [AppState.widgetOrder[i],AppState.widgetOrder[j]]=[AppState.widgetOrder[j],AppState.widgetOrder[i]];
  saveConfigLocal(); scheduleSave();
  renderWidgetsList();
  applyWidgetOrder();
};

