const updateCurrencyRate = function(code,value){
  const v=parseFloat(value);
  AppState.currencyRates[code]= v>0 ? v : (SEED_RATES[code]||1);
  saveConfigLocal(); scheduleSave();
  renderFinance(); renderFinanceChart();
};

const NBU_RATES_URL='https://bank.gov.ua/NBUStatService/v1/statdirectory/exchange?json';

const NBU_RATES_FALLBACK_URL='https://api.allorigins.win/raw?url='+encodeURIComponent('https://bank.gov.ua/NBU_Exchange/exchange?json');

const PRIVAT_RATES_URL='https://api.privatbank.ua/p24api/pubinfo?json&exchange&coursid=5';

function ratesSourceKey(){ return 'xamssRatesSource'; }

const setRatesSource = function(source){
  AppState.ratesSource = source==='privat' ? 'privat' : 'nbu';
  try{ localStorage.setItem(ratesSourceKey(), AppState.ratesSource); }catch(e){}
  renderRatesSourceUI();
  window.updateRatesOnline(true);
};

function renderRatesSourceUI(){
  document.querySelectorAll('#rates-source-filter .filter-chip').forEach(c=>c.classList.toggle('active', c.dataset.source===AppState.ratesSource));
}

async function fetchPrivatCashRates(){
  const res=await fetch(PRIVAT_RATES_URL);
  if(!res.ok) throw new Error('PrivatBank HTTP '+res.status);
  const list=await res.json();
  if(!Array.isArray(list)) throw new Error('unexpected PrivatBank response');
  let updated=0;
  list.forEach(entry=>{
    const code=entry.ccy;
    if(!CURRENCY_LIST.includes(code) || code==='UAH') return;
    const buy=parseFloat(entry.buy), sale=parseFloat(entry.sale);
    if(buy>0 && sale>0){ AppState.currencyRates[code]=Math.round(((buy+sale)/2)*100)/100; updated++; }
  });
  return updated;
}

function ratesUpdatedAtKey(){ return 'xamssRatesUpdatedAt'; }

function renderRatesUpdatedHint(){
  const hint=document.getElementById('rates-updated-hint'); if(!hint) return;
  let at=null;
  try{ at=localStorage.getItem(ratesUpdatedAtKey()); }catch(e){}
  const sourceLabel = AppState.ratesSource==='privat' ? tr('rates_source_privat_short') : tr('rates_source_nbu_short');
  hint.textContent = at ? `${tr('rates_updated_at')} ${sourceLabel} ${new Date(Number(at)).toLocaleString('uk-UA')}` : tr('rates_never_updated');
}

async function fetchLiveRates(){
  let list;
  try{
    const res=await fetch(NBU_RATES_URL);
    if(!res.ok) throw new Error('NBU HTTP '+res.status);
    list=await res.json();
  }catch(primaryErr){
    console.warn('primary NBU rates endpoint failed, trying CORS-relay fallback', primaryErr);
    const res=await fetch(NBU_RATES_FALLBACK_URL);
    if(!res.ok) throw new Error('NBU fallback HTTP '+res.status);
    list=await res.json();
  }
  if(!Array.isArray(list)) throw new Error('unexpected NBU response');
  const wanted=CURRENCY_LIST.filter(c=>c!=='UAH');
  let updated=0;
  wanted.forEach(code=>{
    const entry=list.find(x=>x.cc===code);
    if(entry && entry.rate>0){ AppState.currencyRates[code]=Math.round(entry.rate*100)/100; updated++; }
  });
  if(!updated) throw new Error('none of the tracked currencies found in NBU response');
  if(AppState.ratesSource==='privat'){
    try{ await fetchPrivatCashRates(); }
    catch(privatErr){ console.warn('PrivatBank cash-rate override failed, keeping NBU rates for USD/EUR', privatErr); }
  }
  saveConfigLocal(); scheduleSave();
  try{ localStorage.setItem(ratesUpdatedAtKey(), String(Date.now())); }catch(e){}
  return updated;
}

const updateRatesOnline = async function(silent){
  const btn=document.getElementById('rates-update-btn');
  const widgetBtn=document.getElementById('fx-widget-refresh-btn');
  if(btn) btn.disabled=true;
  if(widgetBtn) widgetBtn.disabled=true;
  try{
    await fetchLiveRates();
    renderRatesList(); renderRatesUpdatedHint(); renderFinance(); renderFinanceChart();
    if(!silent) showToast(tr('rates_update_success'),'check');
  }catch(e){
    console.error('live rates fetch failed', e);
    if(!silent) showToast(tr('rates_update_fail'),'xmark');
  }finally{
    if(btn) btn.disabled=false;
    if(widgetBtn) widgetBtn.disabled=false;
  }
};

const FX_WIDGET_COLORS={USD:'var(--green)', EUR:'var(--blue)', GBP:'var(--purple)', PLN:'var(--orange)'};

