function currentMonthPrefix(){
  const n=new Date();
  return `${n.getFullYear()}-${String(n.getMonth()+1).padStart(2,'0')}`;
}

function catMonthTotal(type,name){
  const p=currentMonthPrefix();
  return AppState.transactions.reduce((s,t)=>(t.type===type&&t.category===name&&t.date&&t.date.startsWith(p))?s+toBase(t.amount,t.currency||'UAH'):s,0);
}

function subMonthTotal(type,name,sub){
  const p=currentMonthPrefix();
  return AppState.transactions.reduce((s,t)=>(t.type===type&&t.category===name&&t.subcategory===sub&&t.date&&t.date.startsWith(p))?s+toBase(t.amount,t.currency||'UAH'):s,0);
}

function renderCategoriesList(){
  const box=document.getElementById('categories-list'); if(!box) return;
  box.innerHTML='';
  const list=AppState.categories[AppState.catMgrType]||[];
  if(!list.length){ box.innerHTML=`<div class="mgr-empty">${tr('cat_empty')}</div>`; return; }
  list.forEach((name,idx)=>{
    const subs=AppState.subcategories[subKey(AppState.catMgrType,name)]||[];
    const open=AppState.expandedCatIdx===idx;
    const row=document.createElement('div');
    row.className='mgr-row';
    row.style.cssText='flex-direction:column;align-items:stretch;gap:10px';
    row.dataset.catName=name;
    row.innerHTML=`
      <div class="cat-row">
        <button type="button" class="drag-handle" aria-label="${tr('cat_drag_title')}">${window.Icon('grip')}</button>
        <span class="icon-badge icon-badge-sm" style="background:${categoryColor(name)}">${window.Icon(categoryIcon(name))}</span>
        <button type="button" class="cat-row-body" onclick="toggleSubcatPanel(${idx})">
          <span class="cat-row-name">${escapeHtml(name)}</span>
          <span class="cat-row-sub">${open?'▾':'▸'} ${tr('cat_subcat_short')}${subs.length?` (${subs.length})`:''} · ${catMonthTotal(AppState.catMgrType,name).toLocaleString('uk-UA')} ${tr('cat_this_month')}</span>
        </button>
        <button class="mgr-del" onclick="openCatActionMenu(${idx})" aria-label="${tr('a11y_more')}">${window.Icon('more')}</button>
      </div>
      ${open?`
      <div style="display:flex;flex-direction:column;gap:8px;padding-top:6px;border-top:1px dashed var(--border)">
        <div style="display:flex;flex-wrap:wrap;gap:6px">
          ${subs.length?subs.map((s,si)=>`<span class="subchip">${escapeHtml(s)} · ${subMonthTotal(AppState.catMgrType,name,s).toLocaleString('uk-UA')} ${tr('cat_this_month')}<button onclick="deleteSubcategory(${idx},${si})" aria-label="${tr('a11y_remove')}">${window.Icon('xmark')}</button></span>`).join(''):`<span class="mgr-empty" style="padding:2px 0">${tr('cat_no_subcats')}</span>`}
        </div>
        <button type="button" class="btn btn-ghost" style="align-self:flex-start;padding:6px 12px;font-size:11px">${window.Icon('plus')}${tr('cat_subcategory')}</button>
      </div>`:''}`;
    if(open){
      const addBtn=row.querySelector('.btn-ghost');
      if(addBtn) addBtn.onclick=()=>addSubcategory(idx);
    }
    const handle=row.querySelector('.drag-handle');
    if(handle) attachCategoryDragHandle(handle, row);
    box.appendChild(row);
  });
}

function attachCategoryDragHandle(handle, row){
  handle.addEventListener('pointerdown', e=>{
    e.preventDefault();
    const box=row.parentNode; if(!box) return;
    handle.setPointerCapture(e.pointerId);
    row.classList.add('dragging');
    function onMove(ev){
      const y=ev.clientY;
      const siblings=[...box.children].filter(r=>r!==row && r.classList.contains('mgr-row'));
      let placed=false;
      for(const sib of siblings){
        const rect=sib.getBoundingClientRect();
        if(y < rect.top+rect.height/2){ box.insertBefore(row, sib); placed=true; break; }
      }
      if(!placed) box.appendChild(row);
    }
    function onUp(){
      handle.removeEventListener('pointermove', onMove);
      handle.removeEventListener('pointerup', onUp);
      handle.removeEventListener('pointercancel', onUp);
      row.classList.remove('dragging');
      const newOrder=[...box.children].filter(r=>r.classList.contains('mgr-row')).map(r=>r.dataset.catName);
      AppState.categories[AppState.catMgrType]=newOrder;
      AppState.expandedCatIdx=null;
      saveConfigLocal(); scheduleSave();
      renderCategoriesList(); fillCats(AppState.currentFinanceType); renderBudgets();
    }
    handle.addEventListener('pointermove', onMove);
    handle.addEventListener('pointerup', onUp);
    handle.addEventListener('pointercancel', onUp);
  });
}

const toggleSubcatPanel = function(idx){
  AppState.expandedCatIdx = AppState.expandedCatIdx===idx ? null : idx;
  renderCategoriesList();
};

const addSubcategory = async function(idx){
  const list=AppState.categories[AppState.catMgrType]; const name=list&&list[idx]; if(!name) return;
  const subName=await uiPrompt(tr('cat_add_subcat_prompt'),'',tr('cat_add_subcat_title'));
  if(subName===null) return;
  const clean=subName.trim(); if(!clean) return;
  const key=subKey(AppState.catMgrType,name);
  if(!AppState.subcategories[key]) AppState.subcategories[key]=[];
  if(AppState.subcategories[key].includes(clean)){ showToast(tr('cat_subcat_exists'),'xmark'); return; }
  AppState.subcategories[key].push(clean);
  saveConfigLocal(); scheduleSave();
  renderCategoriesList();
};

const deleteSubcategory = async function(idx,si){
  const list=AppState.categories[AppState.catMgrType]; const name=list&&list[idx]; if(!name) return;
  const subs=AppState.subcategories[subKey(AppState.catMgrType,name)]; if(!subs||subs[si]===undefined) return;
  if(!(await uiConfirm(tr('cat_delete_subcat_confirm'),{title:tr('cat_delete_subcat_title'),okText:tr('common_delete'),danger:true}))) return;
  subs.splice(si,1);
  saveConfigLocal(); scheduleSave();
  renderCategoriesList();
};

const renameCategory = function(idx,value){
  const list=AppState.categories[AppState.catMgrType]; if(!list||!list[idx]) return;
  const oldName=list[idx];
  const newName=String(value).trim();
  if(!newName){ renderCategoriesList(); return; }
  list[idx]=newName;
  // keep existing transactions consistent with the rename
  AppState.transactions.forEach(t=>{ if(t.type===AppState.catMgrType && t.category===oldName) t.category=newName; });
  AppState.recurring.forEach(r=>{ if(r.type===AppState.catMgrType && r.category===oldName) r.category=newName; });
  if(AppState.budgets[oldName]!==undefined){ AppState.budgets[newName]=AppState.budgets[oldName]; delete AppState.budgets[oldName]; }
  const oldKey=subKey(AppState.catMgrType,oldName);
  if(AppState.subcategories[oldKey]!==undefined){ AppState.subcategories[subKey(AppState.catMgrType,newName)]=AppState.subcategories[oldKey]; delete AppState.subcategories[oldKey]; }
  saveConfigLocal(); saveRecurringLocal();
  const tk=lsKey('tx'); if(tk) localStorage.setItem(tk,JSON.stringify(AppState.transactions));
  scheduleSave();
  renderCategoriesList(); fillCats(AppState.currentFinanceType); renderFinance();
};

const addCategory = async function(){
  const name=await uiPrompt(tr('cat_add_prompt'),'',tr('cat_add_title'));
  if(name===null) return;
  const clean=name.trim(); if(!clean) return;
  if(!AppState.categories[AppState.catMgrType]) AppState.categories[AppState.catMgrType]=[];
  if(AppState.categories[AppState.catMgrType].includes(clean)){ showToast(tr('cat_already_exists'),'xmark'); return; }
  AppState.categories[AppState.catMgrType].push(clean);
  saveConfigLocal(); scheduleSave();
  renderCategoriesList(); fillCats(AppState.currentFinanceType);
};

const deleteCategory = async function(idx){
  const list=AppState.categories[AppState.catMgrType]; if(!list||list[idx]===undefined) return;
  if(!(await uiConfirm(tr('cat_delete_confirm'),{title:tr('cat_delete_title'),okText:tr('common_delete'),danger:true}))) return;
  const removed=list[idx];
  list.splice(idx,1);
  delete AppState.budgets[removed];
  delete AppState.subcategories[subKey(AppState.catMgrType,removed)];
  AppState.expandedCatIdx=null;
  saveConfigLocal(); scheduleSave();
  renderCategoriesList(); fillCats(AppState.currentFinanceType); renderBudgets();
};

const openCatActionMenu = function(idx){
  const list=AppState.categories[AppState.catMgrType]; const name=list&&list[idx]; if(!name) return;
  AppState.catActionIdx=idx;
  document.getElementById('cat-action-title').textContent=name;
  document.getElementById('cat-action-modal').style.display='flex';
};

const catActionEdit = async function(){
  const idx=AppState.catActionIdx; const list=AppState.categories[AppState.catMgrType]; const name=list&&list[idx]; if(!name) return;
  window.closeManagers();
  const newName=await uiPrompt(tr('cat_add_prompt'), name, tr('cat_act_edit'));
  if(newName===null) return;
  window.renameCategory(idx, newName);
};

const catActionShowTx = function(){
  const idx=AppState.catActionIdx; const list=AppState.categories[AppState.catMgrType]; const name=list&&list[idx]; if(!name) return;
  window.closeManagers();
  AppState.txCategoryFilter=name;
  switchTab('finance');
  renderFinance();
  showToast(`${tr('cat_showing')} ${name}`,'search');
};

const catActionDelete = async function(){
  const idx=AppState.catActionIdx;
  window.closeManagers();
  await window.deleteCategory(idx);
};

const openBudgetsManager = function(){
  renderBudgetsManagerList();
  document.getElementById('budgets-modal').style.display='flex';
};

function renderBudgetsManagerList(){
  const box=document.getElementById('budgets-list-mgr'); if(!box) return;
  box.innerHTML='';
  const list=AppState.categories.expense||[];
  if(!list.length){ box.innerHTML=`<div class="mgr-empty">${tr('budgets_empty')}</div>`; return; }
  list.forEach(name=>{
    const val=AppState.budgets[name]||'';
    const row=document.createElement('div');
    row.className='mgr-row budget-row';
    row.innerHTML=`
      <span class="icon-badge icon-badge-sm" style="background:${categoryColor(name)}">${window.Icon(categoryIcon(name))}</span>
      <span class="budget-row-name">${escapeHtml(name)}</span>
      <input type="number" class="mgr-num budget-row-input" min="0" step="0.01" placeholder="0" value="${val}" data-cat="${escapeHtml(name)}" onchange="updateBudget(this.dataset.cat,this.value)">
    `;
    box.appendChild(row);
  });
}

const updateBudget = function(name,value){
  const v=parseFloat(value);
  if(!v||v<=0) delete AppState.budgets[name]; else AppState.budgets[name]=v;
  saveConfigLocal(); scheduleSave();
  renderBudgets();
};

export function renderBudgets(){
  const section=document.getElementById('budgets-section');
  const box=document.getElementById('budgets-list');
  if(!section||!box) return;
  const entries=Object.entries(AppState.budgets).filter(([cat,limit])=>limit>0 && (AppState.categories.expense||[]).includes(cat));
  if(!entries.length){ section.style.display='none'; return; }
  section.style.display='block';
  const now=new Date();
  const prefix=`${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}`;
  box.innerHTML='';
  entries.sort((a,b)=>a[0].localeCompare(b[0],'uk')).forEach(([cat,limit])=>{
    const spent=AppState.transactions.reduce((s,t)=>(t.type==='expense'&&t.category===cat&&t.date&&t.date.startsWith(prefix))?s+toBase(t.amount,t.currency||'UAH'):s,0);
    const pct=Math.min(100,Math.round(spent/limit*100));
    const over=spent>limit;
    const color=over?'var(--red2)':(pct>=80?'var(--orange2)':'var(--green2)');
    const row=document.createElement('div');
    row.style.marginBottom='14px';
    row.innerHTML=`
      <div style="display:flex;justify-content:space-between;align-items:center;font-size:12px;font-weight:700;margin-bottom:4px;gap:8px">
        <span style="display:flex;align-items:center;gap:8px;color:var(--text-strong);min-width:0"><span class="icon-badge icon-badge-sm" style="background:${categoryColor(cat)};flex-shrink:0">${window.Icon(categoryIcon(cat))}</span><span style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escapeHtml(cat)}</span></span>
        <span style="color:${color};white-space:nowrap">${spent.toLocaleString('uk-UA')} / ${limit.toLocaleString('uk-UA')} грн</span>
      </div>
      <div class="salary-bar-wrap"><div class="salary-bar-fill" style="width:${pct}%;background:${color}"></div></div>
      ${over?`<div style="font-size:11px;color:var(--red2);font-weight:700;margin-top:3px">${tr('budgets_over_by')} ${(spent-limit).toLocaleString('uk-UA')} грн</div>`:''}
    `;
    box.appendChild(row);
  });
}

const openRecurringManager = function(){
  renderRecurringList();
  document.getElementById('recurring-modal').style.display='flex';
};

function renderRecurringList(){
  const box=document.getElementById('recurring-list'); if(!box) return;
  box.innerHTML='';
  if(!AppState.recurring.length){ box.innerHTML=`<div class="mgr-empty">${tr('recurring_empty')}</div>`; return; }
  AppState.recurring.forEach(r=>{
    const catList=AppState.categories[r.type]||[];
    const row=document.createElement('div');
    row.className='debt-row'+(r.active===false?' recur-paused':'');
    row.innerHTML=`
      <div class="debt-field" style="flex:1 1 100px">
        <span class="debt-field-label">${tr('recurring_type')}</span>
        <select onchange="updateRecurring('${r.id}','type',this.value)">
          <option value="income" ${r.type==='income'?'selected':''}>${tr('cat_income')}</option>
          <option value="expense" ${r.type==='expense'?'selected':''}>${tr('cat_expense')}</option>
        </select>
      </div>
      <div class="debt-field" style="flex:1 1 90px">
        <span class="debt-field-label">${tr('recurring_amount')}</span>
        <input type="number" min="0.01" step="0.01" value="${r.amount||''}" onchange="updateRecurring('${r.id}','amount',this.value)">
      </div>
      <div class="debt-field" style="flex:1 1 130px">
        <span class="debt-field-label">${tr('finance_category')}</span>
        <select onchange="updateRecurring('${r.id}','category',this.value)">
          ${catList.map(c=>`<option value="${escapeHtml(c)}" ${r.category===c?'selected':''}>${escapeHtml(c)}</option>`).join('')}
        </select>
      </div>
      <div class="debt-field" style="flex:1 1 120px">
        <span class="debt-field-label">${tr('finance_wallet')}</span>
        <select onchange="updateRecurring('${r.id}','wallet',this.value)">
          ${AppState.wallets.map(w=>`<option value="${w.id}" ${r.wallet===w.id?'selected':''}>${escapeHtml(w.name)}</option>`).join('')}
        </select>
      </div>
      <div class="debt-field" style="flex:1 1 110px">
        <span class="debt-field-label">${tr('recurring_frequency')}</span>
        <select onchange="updateRecurring('${r.id}','frequency',this.value)">
          <option value="daily" ${r.frequency==='daily'?'selected':''}>${tr('recurring_daily')}</option>
          <option value="weekly" ${r.frequency==='weekly'?'selected':''}>${tr('recurring_weekly')}</option>
          <option value="monthly" ${(!r.frequency||r.frequency==='monthly')?'selected':''}>${tr('recurring_monthly')}</option>
        </select>
      </div>
      <div class="debt-field" style="flex:1 1 132px">
        <span class="debt-field-label">${tr('recurring_next_date')}</span>
        <input type="date" value="${r.nextDate||''}" onchange="updateRecurring('${r.id}','nextDate',this.value)">
      </div>
      <div class="debt-field" style="flex:1 1 100%;flex-direction:row;align-items:center;justify-content:space-between;gap:10px">
        <label style="display:flex;align-items:center;gap:8px;cursor:pointer;min-width:0">
          <input type="checkbox" class="rchk" ${r.active!==false?'checked':''} onchange="updateRecurring('${r.id}','active',this.checked)">
          <span class="debt-field-label" style="text-transform:none;font-size:11px;white-space:nowrap">${tr('recurring_active')}</span>
        </label>
        <button class="debt-row-del" style="align-self:auto" onclick="deleteRecurring('${r.id}')" aria-label="${tr('common_delete')}">${window.Icon('trash')}</button>
      </div>
    `;
    box.appendChild(row);
    row.querySelectorAll('select').forEach(enhanceSelect);
    row.querySelectorAll('input[type=date]').forEach(enhanceDateInput);
  });
}

const updateRecurring = function(id,field,value){
  const r=AppState.recurring.find(x=>x.id===id); if(!r) return;
  if(field==='amount') r.amount=parseFloat(value)||0;
  else if(field==='active') r.active=!!value;
  else if(field==='type'){ r.type=value; r.category=(AppState.categories[value]||[])[0]||tr('cat_other'); }
  else r[field]=value;
  saveRecurringLocal(); scheduleSave();
  renderRecurringList();
};

const addRecurring = function(){
  const type='expense';
  const category=(AppState.categories.expense||[])[0]||tr('cat_other');
  const wallet=(AppState.wallets[0]&&AppState.wallets[0].id)||'';
  const today=new Date().toISOString().split('T')[0];
  AppState.recurring.push({id:uid('rec'), type, amount:0, category, wallet, frequency:'monthly', nextDate:today, active:true, comment:''});
  saveRecurringLocal(); scheduleSave();
  renderRecurringList();
  showToast(tr('recurring_added'),'plus');
};

const deleteRecurring = async function(id){
  if(!(await uiConfirm(tr('recurring_delete_confirm'),{title:tr('recurring_delete_title'),okText:tr('common_delete'),danger:true}))) return;
  AppState.recurring=AppState.recurring.filter(r=>r.id!==id);
  saveRecurringLocal(); scheduleSave();
  renderRecurringList();
};

// Top-level statements that DO something immediately (as opposed to a
// plain declaration) - deferred into this function and called from
// app.js only after every module in the import graph has finished
// evaluating, so nothing here can hit a temporal-dead-zone reference to
// another chunk's not-yet-initialized export (this is exactly the class
// of bug that broke 'auth' being read before core.js's declaration of it
// had run, when this was still ordinary top-level code in this file).
export function __init_settings_managers__(){
window.closeManagers=function(e){
  if(e && e.target && !e.target.classList.contains('modal-overlay')) return;
  ['shift-types-modal','wallets-modal','categories-modal','budgets-modal','goals-modal','recurring-modal','rates-modal','widgets-modal','pin-settings-modal','tags-modal','cat-action-modal','rules-modal','premium-modal','profiles-modal','link-phone-modal','profile-avatar-pick-modal','color-pick-modal','tx-form-modal','debt-form-modal'].forEach(id=>{
    const el=document.getElementById(id); if(el) el.style.display='none';
  });
};
window.openShiftTypesManager = openShiftTypesManager;
window.toggleShiftTypeEdit = toggleShiftTypeEdit;
window.updateShiftType = updateShiftType;
window.addShiftType = addShiftType;
window.deleteShiftType = deleteShiftType;
window.openWalletsManager = openWalletsManager;
window.updateWallet = updateWallet;
window.addWallet = addWallet;
window.deleteWallet = deleteWallet;
window.openRatesManager = openRatesManager;
window.toggleWidget = toggleWidget;
window.moveWidget = moveWidget;
window.openWidgetsManager = openWidgetsManager;
window.updateCurrencyRate = updateCurrencyRate;
try{ const s=localStorage.getItem(ratesSourceKey()); if(s==='privat'||s==='nbu') AppState.ratesSource=s; }catch(e){}
window.setRatesSource = setRatesSource;
window.updateRatesOnline = updateRatesOnline;
window.renderFxConverter=renderFxConverter;
window.swapFxConverter = swapFxConverter;
window.refreshFxWidget = refreshFxWidget;
window.openCategoriesManager = openCategoriesManager;
window.setCatMgrType = setCatMgrType;
window.toggleSubcatPanel = toggleSubcatPanel;
window.addSubcategory = addSubcategory;
window.deleteSubcategory = deleteSubcategory;
window.renameCategory = renameCategory;
window.addCategory = addCategory;
window.deleteCategory = deleteCategory;
window.openCatActionMenu = openCatActionMenu;
window.catActionEdit = catActionEdit;
window.catActionShowTx = catActionShowTx;
window.catActionDelete = catActionDelete;
window.openBudgetsManager = openBudgetsManager;
window.updateBudget = updateBudget;
window.openRecurringManager = openRecurringManager;
window.updateRecurring = updateRecurring;
window.addRecurring = addRecurring;
window.deleteRecurring = deleteRecurring;
}
